    private void OnMotorSearchTextChanged(ChangeEventArgs changeEventArgs, string columnTitle)
    {
        string searchText = changeEventArgs.Value.ToString();
        IsGridViewFiltered = true;

        switch (columnTitle)
        {
            case "CoverNoteNo":
                filteredMotorList = MotorList.Where(motor => motor.CoverNoteNo.ToString().Contains(searchText)).ToList();
                break;
            case "QuotationNo":
                filteredMotorList = MotorList.Where(motor => motor.QuotationNo.ToString().Contains(searchText)).ToList();
                break;
            case "JPJStatus":
                filteredMotorList = MotorList.Where(motor => motor.JPJStatus.ToString().Contains(searchText)).ToList();
                break;
            case "AgentCode":
                filteredMotorList = MotorList.Where(motor => motor.AgentCode.ToString().Contains(searchText)).ToList();
                break;
            case "IssueDate":
                filteredMotorList = MotorList.Where(motor => motor.IssueDate.ToString().Contains(searchText)).ToList();
                break;
            default:
                Console.WriteLine("Default case");
                break;
        }
    }

    private async Task update()
    {
        if (covernote == null)
        {
            ToastService.ShowWarning("Please enter Cover Note No.");
        }
        else if (covernote == "")
        {
            IsGridViewFiltered = true;
            AllMtrList = filteredAllMtrList = await MotorPolicyService.SearchMotor(covernote.Replace(" ", ""));
            StateHasChanged();

            ToastService.ShowWarning("Please enter Cover Note No.");
        }
        else
        {
            string[] result = covernote.Replace(" ", "").Split(new string[] { "," }, StringSplitOptions.RemoveEmptyEntries);

            foreach (string strCN in result)
            {
                i = i + 1;

                AllMtrList = filteredAllMtrList = await MotorPolicyService.GetPendMotor(strCN);

                if (AllMtrList == null || AllMtrList.Count == 0)
