                ErrCN = ErrCN + " is";
            }
            else
            {
                ErrCN = ErrCN + " are";
            }

            i = 0;

            if (Err == true)
            {
                IsGridViewFiltered = true;
                AllMtrList = filteredAllMtrList = await MotorPolicyService.SearchMotor(covernote.Replace(" ", ""));
                StateHasChanged();

                ToastService.ShowError(ErrCN + " not under Policy Issued/ pending JPJ");
            }
            else
            {
                MotorPolicyService.UpdStatus(covernote.Replace(" ", ""));
                IsGridViewFiltered = true;
                AllMtrList = filteredAllMtrList = await MotorPolicyService.SearchMotor(covernote.Replace(" ", ""));
                MotorList = filteredMotorList = await MotorPolicyService.GetIssueMotor();
                StateHasChanged();
            }
        }
    }

