    private async Task addZipEntry(string PathStr)
    {
        DirectoryInfo di = new DirectoryInfo(PathStr);

        foreach (DirectoryInfo item in di.GetDirectories())
        {
            await addZipEntry(item.FullName);
        }

        using (MemoryStream ms = new MemoryStream())
        {
            using (ZipOutputStream zipSream = new ZipOutputStream(ms))
            {
                foreach (FileInfo item in di.GetFiles())
                {
                    FileStream fs = File.OpenRead(item.FullName);
                    byte[] buffer = new byte[fs.Length];
                    fs.Read(buffer, 0, buffer.Length);
                    string strEntryName = item.FullName;
                    ZipEntry entry = new ZipEntry(strEntryName);
                    zipSream.PutNextEntry(entry);
                    zipSream.Write(buffer, 0, buffer.Length);
                    fs.Close();
                }
            }

            await FileSaver.SaveAsBase64("Renewal_CN.zip", Convert.ToBase64String(ms.ToArray()), "application/zip");
        }
    }

